844	// harnessHealthyViaService reports whether the upstream service has an active
845	// failure cooldown recorded against the given harness. The upstream service's
846	// RouteStatus is the authoritative health source, so one worker's
847	// RecordRouteAttempt benefits every other consumer. When RouteStatus is
848	// unavailable (e.g. fresh service with no routes yet) the harness is
849	// considered healthy.
850	func harnessHealthyViaService(ctx context.Context, svc agentlib.FizeauService, harness string) bool {
851		if svc == nil || harness == "" {
852			return true
853		}
854		report, err := svc.RouteStatus(ctx)
855		if err != nil || report == nil {
856			return true
857		}
858		for _, route := range report.Routes {
859			for _, cand := range route.Candidates {
860				if cand.Provider != harness {
861					continue
862				}
863				if !cand.Healthy {
864					return false
865				}
866			}
867		}
868		return true
869	}
