104	// newAgentWorkersStopCommand wires the `ddx agent workers stop` subcommand.
105	// Targeting modes are mutually exclusive:
106	//
107	//	ddx agent workers stop <worker-id>     — one worker by id
108	//	ddx agent workers stop --all-over <d>  — every running worker older than <d>
109	//	ddx agent workers stop --state <state> — every worker in <state>
110	//	ddx agent workers stop --bead <id>     — the worker assigned to <bead-id>
111	//
112	// Each match POSTs /api/agent/workers/{id}/stop on the running ddx server,
113	// which triggers the graceful SIGTERM → grace → SIGKILL path in
114	// WorkerManager.Stop. Returns a non-zero exit code if any target fails.
115	func (f *CommandFactory) newAgentWorkersStopCommand() *cobra.Command {
116		cmd := &cobra.Command{
