141	func (f *CommandFactory) runAgentWorkersStop(cmd *cobra.Command, args []string) error {
142		allOver, _ := cmd.Flags().GetDuration("all-over")
143		stateFilter, _ := cmd.Flags().GetString("state")
144		beadFilter, _ := cmd.Flags().GetString("bead")
145		projectFlag, _ := cmd.Flags().GetString("project")
146		asJSON, _ := cmd.Flags().GetBool("json")
147	
148		// Enforce that the operator picks exactly one targeting mode.
149		modes := 0
150		if len(args) > 0 {
151			modes++
152		}
153		if allOver > 0 {
154			modes++
155		}
156		if stateFilter != "" {
157			modes++
158		}
159		if beadFilter != "" {
160			modes++
161		}
162		if modes == 0 {
163			return fmt.Errorf("specify a worker id or one of --all-over, --state, --bead")
164		}
165		if modes > 1 {
166			return fmt.Errorf("specify exactly one of: <worker-id>, --all-over, --state, --bead")
167		}
168	
169		projectRoot := projectFlag
170		if projectRoot == "" {
171			projectRoot = gitpkg.FindProjectRoot(f.WorkingDir)
172		}
173	
174		var targets []string
175		if len(args) > 0 {
176			targets = []string{args[0]}
177		} else {
178			workers := collectAgentWorkers(projectRoot)
179			now := time.Now()
180			for _, wk := range workers {
181				if wk.Kind == "local" {
182					// Local (execute-bead) workers are not reachable through the
183					// server stop endpoint. Skip them here — operators must stop
184					// them via the worktree's own lifecycle.
185					continue
186				}
187				if allOver > 0 {
188					if wk.State != "running" || wk.StartedAt.IsZero() {
189						continue
190					}
191					if now.Sub(wk.StartedAt) <= allOver {
192						continue
193					}
194				}
195				if stateFilter != "" && wk.State != stateFilter {
196					continue
197				}
198				if beadFilter != "" && wk.BeadID != beadFilter {
199					continue
200				}
201				targets = append(targets, wk.ID)
202			}
203		}
204	
205		if len(targets) == 0 {
206			fmt.Fprintln(cmd.OutOrStdout(), "no matching workers")
207			return nil
208		}
209	
210		base := resolveServerURL(projectRoot)
211		client := newLocalServerClient()
212	
213		var firstErr error
214		for _, id := range targets {
215			reqURL := base + "/api/agent/workers/" + id + "/stop"
216			req, err := http.NewRequestWithContext(cmd.Context(), http.MethodPost, reqURL, nil)
217			if err != nil {
218				if firstErr == nil {
219					firstErr = err
220				}
221				continue
222			}
223			resp, err := client.Do(req)
224			if err != nil {
225				fmt.Fprintf(cmd.ErrOrStderr(), "stop %s: %v\n", id, err)
226				if firstErr == nil {
227					firstErr = err
228				}
229				continue
230			}
231			body, _ := io.ReadAll(resp.Body)
232			_ = resp.Body.Close()
233			if resp.StatusCode != http.StatusOK {
234				msg := strings.TrimSpace(string(body))
235				fmt.Fprintf(cmd.ErrOrStderr(), "stop %s: server error (%d): %s\n", id, resp.StatusCode, msg)
236				if firstErr == nil {
237					firstErr = fmt.Errorf("server error (%d) for %s", resp.StatusCode, id)
238				}
239				continue
240			}
241			if asJSON {
242				fmt.Fprintln(cmd.OutOrStdout(), strings.TrimSpace(string(body)))
243			} else {
244				fmt.Fprintf(cmd.OutOrStdout(), "stopping %s\n", id)
245			}
246		}
247		return firstErr
248	}
