377	// scanLocalBeadWorkers scans .ddx/executions/*/manifest.json and checks
378	// active git worktrees to find locally-running execute-bead executions
379	// not already covered by the server.
380	func scanLocalBeadWorkers(projectRoot string, serverAttemptIDs map[string]bool) []agentWorkerDisplay {
381		execDir := filepath.Join(projectRoot, ".ddx", "executions")
382		entries, err := os.ReadDir(execDir)
383		if err != nil {
384			return nil
385		}
386	
387		active := agentActiveWorktrees(projectRoot)
388	
389		var out []agentWorkerDisplay
390		for _, entry := range entries {
391			if !entry.IsDir() {
392				continue
393			}
394			manifestPath := filepath.Join(execDir, entry.Name(), "manifest.json")
395			data, err := os.ReadFile(manifestPath)
396			if err != nil {
397				continue
398			}
399			var m agentLocalManifest
400			if err := json.Unmarshal(data, &m); err != nil {
401				continue
402			}
403	
404			// Skip if covered by server (attempt already tracked)
405			if serverAttemptIDs[m.AttemptID] {
406				continue
407			}
408			// Skip if worker_id is set — server-submitted executions are in the server list
409			if m.WorkerID != "" {
410				continue
411			}
412	
413			// Check if the worktree for this attempt is still active
414			wtPath := agentLocalWorktreePath(m.BeadID, m.AttemptID)
415			if !active[wtPath] {
416				continue
417			}
418	
419			elapsed := time.Since(m.CreatedAt)
420			d := agentWorkerDisplay{
421				ID:        "local-" + m.AttemptID,
422				Kind:      "local",
423				State:     "running",
424				BeadID:    m.BeadID,
425				BeadTitle: m.Bead.Title,
426				Harness:   m.Requested.Harness,
427				Model:     m.Requested.Model,
428				StartedAt: m.CreatedAt,
429				ElapsedMS: elapsed.Milliseconds(),
430			}
431			out = append(out, d)
432		}
433		return out
434	}
