605	// agentFormatElapsed returns a human-readable elapsed duration like "4m32s".
606	// Uses elapsedMS if positive; otherwise derives from startedAt.
607	func agentFormatElapsed(elapsedMS int64, startedAt time.Time) string {
608		var d time.Duration
609		if elapsedMS > 0 {
610			d = time.Duration(elapsedMS) * time.Millisecond
611		} else if !startedAt.IsZero() {
612			d = time.Since(startedAt)
613			if d < 0 {
614				d = 0
615			}
616		} else {
617			return "-"
618		}
619		h := int(d.Hours())
620		m := int(d.Minutes()) % 60
621		s := int(d.Seconds()) % 60
622		if h > 0 {
623			return fmt.Sprintf("%dh%dm%ds", h, m, s)
624		}
625		if m > 0 {
626			return fmt.Sprintf("%dm%ds", m, s)
627		}
628		return fmt.Sprintf("%ds", s)
629	}
